class Node:
    def __init__(self, value):
        self.value = value
        self.left = None
        self.right = None

def insert(root, char):
    if root is None:
        return Node(char)
    if char < root.value:
        root.left = insert(root.left, char)
    elif char > root.value:
        root.right = insert(root.right, char)
    return root

def recursive_process(sequence, index, tree_root):
    if index >= len(sequence):
        return tree_root
    char = sequence[index].lower()
    tree_root = insert(tree_root, char)
    return recursive_process(sequence, index + 1, tree_root)

